using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            TestHelpers.DrainNotificationQueue();
            _sut?.Dispose();
        }

        [TestMethod]
        public void SendNotification_Create_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Course (ID: 42) has been created", DisplayName = "CREATE without display name")]
        [DataRow(EntityOperation.UPDATE, "Course (ID: 42) has been updated", DisplayName = "UPDATE without display name")]
        [DataRow(EntityOperation.DELETE, "Course (ID: 42) has been deleted", DisplayName = "DELETE without display name")]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage(EntityOperation op, string expected)
        {
            // Act
            _sut.SendNotification("Course", "42", op, "user1");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expected, notification.Message);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Dept 'Math' has been created", DisplayName = "CREATE with display name")]
        [DataRow(EntityOperation.UPDATE, "Dept 'Math' has been updated", DisplayName = "UPDATE with display name")]
        [DataRow(EntityOperation.DELETE, "Dept 'Math' has been deleted", DisplayName = "DELETE with display name")]
        public void SendNotification_WithDisplayName_UsesNameInMessage(EntityOperation op, string expected)
        {
            // Act
            _sut.SendNotification("Dept", "1", "Math", op, "admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expected, notification.Message);
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToRecentTime()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before);
            Assert.IsTrue(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            // Arrange
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            // Act & Assert
            Assert.AreEqual("A", _sut.ReceiveNotification().EntityType);
            Assert.AreEqual("B", _sut.ReceiveNotification().EntityType);
            Assert.AreEqual("C", _sut.ReceiveNotification().EntityType);
            Assert.IsNull(_sut.ReceiveNotification());
        }

        [TestMethod]
        public void SendNotification_ExceedsMaxQueueLength_TrimsOldest()
        {
            // Arrange - fill beyond 500 cap
            for (int i = 0; i < 510; i++)
            {
                _sut.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
            }

            // Act - count remaining
            int count = 0;
            while (_sut.ReceiveNotification() != null) count++;

            // Assert - should be at or below 500
            Assert.IsTrue(count <= 500, $"Queue should be capped at 500, but had {count}");
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - MarkAsRead is a no-op but should not throw
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert
            _sut.Dispose();
            // Can still use after dispose (no-op implementation)
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);
            Assert.IsNotNull(_sut.ReceiveNotification());
        }

        [TestMethod]
        public void SendNotification_EmptyDisplayName_UsesIdFormat()
        {
            // Act
            _sut.SendNotification("Student", "5", "", EntityOperation.UPDATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student (ID: 5) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WhitespaceDisplayName_UsesIdFormat()
        {
            // Act
            _sut.SendNotification("Student", "5", "   ", EntityOperation.DELETE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student (ID: 5) has been deleted", notification.Message);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPropertiesCorrectly()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(3, list.Count);
        }

        [TestMethod]
        [DataRow(1, false, DisplayName = "First page has no previous")]
        [DataRow(2, true, DisplayName = "Second page has previous")]
        [DataRow(3, true, DisplayName = "Third page has previous")]
        public void HasPreviousPage_ReturnsCorrectly(int pageIndex, bool expected)
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

            // Assert
            Assert.AreEqual(expected, list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 3, true, DisplayName = "First of 3 pages has next")]
        [DataRow(3, 3, false, DisplayName = "Last page has no next")]
        [DataRow(2, 3, true, DisplayName = "Middle page has next")]
        public void HasNextPage_ReturnsCorrectly(int pageIndex, int totalPages, bool expected)
        {
            // Arrange - totalPages = ceil(count/pageSize)
            int pageSize = 10;
            int count = totalPages * pageSize;
            var list = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

            // Assert
            Assert.AreEqual(expected, list.HasNextPage);
        }

        [TestMethod]
        [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 = 4 pages")]
        [DataRow(9, 3, 3, DisplayName = "9 items, page size 3 = 3 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 = 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items = 0 pages")]
        public void TotalPages_CalculatedCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages); // ceil(25/10) = 3
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result[0]); // second page starts at 11
            Assert.AreEqual(20, result[9]);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 10);

            // Assert
            Assert.AreEqual(3, result.PageIndex);
            Assert.AreEqual(5, result.Count); // only 5 items on last page
            Assert.AreEqual(21, result[0]);
            Assert.AreEqual(25, result[4]);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 5).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 3);

            // Assert
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(2, result.TotalPages);
            Assert.AreEqual(3, result.Count);
            Assert.AreEqual(1, result[0]);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_SingleItemSinglePage_NoNavigation()
        {
            // Arrange
            var source = new[] { 42 }.AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }
    }
}

using System;
using System.Collections.Generic;
using ContosoUniversity.Models;
