    {
        [TestMethod]
        [DataRow("Doe", "John", "Doe, John", DisplayName = "Standard name")]
        [DataRow("Smith", "Jane", "Smith, Jane", DisplayName = "Another name")]
        [DataRow("", "", ", ", DisplayName = "Empty names")]
        public void Person_FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
        {
            // Arrange - use Student as concrete implementation of Person
            var student = new Student { LastName = lastName, FirstMidName = firstName };

            // Act & Assert
            Assert.AreEqual(expected, student.FullName);
        }

        [TestMethod]
        public void Student_InheritsPerson_HasEnrollmentDate()
        {
            // Arrange
            var date = new DateTime(2023, 9, 1);
            var student = new Student
            {
                ID = 1,
                LastName = "Doe",
                FirstMidName = "John",
                EnrollmentDate = date
            };

            // Assert
            Assert.AreEqual(1, student.ID);
            Assert.AreEqual("Doe", student.LastName);
            Assert.AreEqual("John", student.FirstMidName);
            Assert.AreEqual(date, student.EnrollmentDate);
            Assert.AreEqual("Doe, John", student.FullName);
        }

