        public void Instructor_InheritsPerson_HasHireDate()
        {
            // Arrange
            var date = new DateTime(2000, 1, 15);
            var instructor = new Instructor
            {
                ID = 5,
                LastName = "Smith",
                FirstMidName = "Jane",
                HireDate = date
            };

            // Assert
            Assert.AreEqual(5, instructor.ID);
            Assert.AreEqual("Smith, Jane", instructor.FullName);
            Assert.AreEqual(date, instructor.HireDate);
