using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateContext();
            SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            TestHelpers.DrainNotificationQueue();
            _controller?.Dispose();
            _context?.Dispose();
        }

        private static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
                new Student { FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Yan", LastName = "Li", EnrollmentDate = DateTime.Parse("2012-09-01") }
            );
            context.SaveChanges();
        }

        // --- Index Tests ---

        [TestMethod]
        public void Index_DefaultSort_ReturnsSortedByLastNameAsc()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
        }

        [TestMethod]
        public void Index_NameDesc_ReturnsSortedByLastNameDesc()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual("Li", model[0].LastName);
        }

        [TestMethod]
        public void Index_DateSort_ReturnsSortedByDateAsc()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(DateTime.Parse("2010-09-01"), model[0].EnrollmentDate);
        }

        [TestMethod]
        public void Index_DateDesc_ReturnsSortedByDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(DateTime.Parse("2013-09-01"), model[0].EnrollmentDate);
        }

        [TestMethod]
        public void Index_SearchByLastName_FiltersCorrectly()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            var result = _controller.Index(null, null, "Yan", null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Li", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchWithNoResults_ReturnsEmptyList()
        {
            var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Index_CurrentFilter_MaintainedWhenSearchStringNull()
        {
            _controller.Index(null, "Alexander", null, null);

            Assert.AreEqual("Alexander", _controller.ViewBag.CurrentFilter);
        }

        [TestMethod]
        public void Index_NewSearch_ResetsPageTo1()
        {
            // A new searchString should reset page to 1
            var result = _controller.Index(null, null, "A", 5) as ViewResult;

            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParms()
        {
            _controller.Index(null, null, null, null);

            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_SortOrderDate_SetsDateDescParm()
        {
            _controller.Index("Date", null, null, null);

            Assert.AreEqual("", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
        }

        // --- Details Tests ---

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Arrange - add a student with enrollments for the Include to work
            var student = _context.Students.First();

            // Act
            var result = _controller.Details(student.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        // --- Create GET Tests ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        // --- Create POST Tests ---

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Create_Post_ValidStudent_AddsToDatabase()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.IsTrue(_context.Students.Any(s => s.LastName == "NewStudent"));
        }

        [TestMethod]
        public void Create_Post_MinDateEnrollment_ReturnsViewWithError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        [TestMethod]
        public void Create_Post_DateBefore1753_ReturnsViewWithError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
        }

        // --- Edit GET Tests ---

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();

            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.AreEqual(student.ID, model.ID);
        }

        // --- Edit POST Tests ---

        [TestMethod]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.First();
            // Detach to avoid tracking conflict
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = student.ID,
                LastName = "UpdatedLast",
                FirstMidName = "UpdatedFirst",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Edit(updatedStudent) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_MinDate_ReturnsViewWithError()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        // --- Delete GET Tests ---

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();

            var result = _controller.Delete(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.AreEqual(student.ID, model.ID);
        }

        // --- DeleteConfirmed Tests ---

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            var student = _context.Students.First();
            int id = student.ID;

            var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsFalse(_context.Students.Any(s => s.ID == id));
        }

        // --- Notification Integration ---

        [TestMethod]
        public void Create_Post_ValidStudent_SendsCreateNotification()
        {
            var student = new Student
            {
                LastName = "NotifyTest",
                FirstMidName = "Create",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            var svc = new ContosoUniversity.Services.NotificationService();
            var notification = svc.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.IsTrue(notification.Message.Contains("Student"));
        }

        [TestMethod]
        public void DeleteConfirmed_SendsDeleteNotification()
        {
            var student = _context.Students.First();

            _controller.DeleteConfirmed(student.ID);

            var svc = new ContosoUniversity.Services.NotificationService();
            var notification = svc.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("DELETE", notification.Operation);
        }
    }
}

using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateContext();
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            TestHelpers.DrainNotificationQueue();
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void About_EmptyDb_ReturnsViewWithEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void About_WithStudents_ReturnsGroupedData()
        {
