namespace ContosoUniversity.Tests.Data
{
    [TestClass]
    public sealed class SchoolContextTests
    {
        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            using var context = TestHelpers.CreateContext();
            context.Students.Add(new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            });
            context.SaveChanges();

            Assert.AreEqual(1, context.Students.Count());
            Assert.AreEqual("Student", context.Students.First().LastName);
        }

        [TestMethod]
        public void SchoolContext_CourseAssignment_CompositeKey()
        {
            using var context = TestHelpers.CreateContext();

            var instructor = new Instructor { FirstMidName = "A", LastName = "B", HireDate = DateTime.Now };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var dept = new Department { Name = "Dept", Budget = 100, StartDate = DateTime.Now };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course { CourseID = 100, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
            context.Courses.Add(course);
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            });
            context.SaveChanges();

            var ca = context.CourseAssignments.Find(course.CourseID, instructor.ID);
            Assert.IsNotNull(ca);
        }

        [TestMethod]
        public void SchoolContext_TPH_DiscriminatorWorks()
        {
            using var context = TestHelpers.CreateContext();

            context.Students.Add(new Student { FirstMidName = "S", LastName = "Student", EnrollmentDate = DateTime.Now });
            context.Instructors.Add(new Instructor { FirstMidName = "I", LastName = "Instructor", HireDate = DateTime.Now });
            context.SaveChanges();

            // People should include both
            Assert.AreEqual(2, context.People.Count());
            Assert.AreEqual(1, context.Students.Count());
            Assert.AreEqual(1, context.Instructors.Count());
        }

        [TestMethod]
        public void SchoolContext_OfficeAssignment_OneToOneRelationship()
        {
            using var context = TestHelpers.CreateContext();

            var instructor = new Instructor { FirstMidName = "A", LastName = "B", HireDate = DateTime.Now };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            });
            context.SaveChanges();

            var oa = context.OfficeAssignments.Find(instructor.ID);
            Assert.IsNotNull(oa);
            Assert.AreEqual("Room 101", oa.Location);
        }

        [TestMethod]
        public void SchoolContext_DbSets_AllExist()
        {
            using var context = TestHelpers.CreateContext();

            Assert.IsNotNull(context.Courses);
            Assert.IsNotNull(context.Enrollments);
            Assert.IsNotNull(context.Departments);
            Assert.IsNotNull(context.OfficeAssignments);
            Assert.IsNotNull(context.CourseAssignments);
            Assert.IsNotNull(context.People);
            Assert.IsNotNull(context.Students);
            Assert.IsNotNull(context.Instructors);
            Assert.IsNotNull(context.Notifications);
        }
    }
