+        }
+
+        [TestMethod]
+        public void GetNotifications_WithNotifications_ReturnsUpTo10()
+        {
+            // Arrange
+            var svc = new NotificationService();
+            for (int i = 0; i < 15; i++)
+            {
+                svc.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
+            }
+
+            // Act
+            var result = _controller.GetNotifications();
+
+            // Assert
+            Assert.IsNotNull(result.Value);
+            // After reading 10, 5 should remain in queue
+            int remaining = 0;
+            while (svc.ReceiveNotification() != null) remaining++;
+            Assert.AreEqual(5, remaining);
+        }
+
+        [TestMethod]
+        public void GetNotifications_FewerThan10_ReturnsAll()
+        {
