+            svc.SendNotification("A", "1", EntityOperation.CREATE);
+            svc.SendNotification("B", "2", EntityOperation.UPDATE);
+
+            var result = _controller.GetNotifications();
+
+            Assert.IsNotNull(result.Value);
+            // Queue should be empty
+            Assert.IsNull(svc.ReceiveNotification());
+        }
