+            Assert.AreEqual(8, context.CourseAssignments.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsEnrollments()
+        {
+            using var context = TestHelpers.CreateContext();
+            DbInitializer.Initialize(context);
+
+            Assert.AreEqual(11, context.Enrollments.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_CalledTwice_IsIdempotent()
+        {
+            using var context = TestHelpers.CreateContext();
+            DbInitializer.Initialize(context);
+            DbInitializer.Initialize(context);
+
+            // Counts should remain the same
+            Assert.AreEqual(8, context.Students.Count());
+            Assert.AreEqual(7, context.Courses.Count());
+            Assert.AreEqual(11, context.Enrollments.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsStudentWithCorrectData()
+        {
+            using var context = TestHelpers.CreateContext();
+            DbInitializer.Initialize(context);
+
+            var carson = context.Students.Single(s => s.LastName == "Alexander");
+            Assert.AreEqual("Carson", carson.FirstMidName);
+            Assert.AreEqual(DateTime.Parse("2010-09-01"), carson.EnrollmentDate);
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsEnrollmentsWithGrades()
+        {
+            using var context = TestHelpers.CreateContext();
+            DbInitializer.Initialize(context);
+
+            var enrollmentsWithGrade = context.Enrollments.Where(e => e.Grade != null).Count();
+            var enrollmentsWithoutGrade = context.Enrollments.Where(e => e.Grade == null).Count();
+
+            Assert.IsTrue(enrollmentsWithGrade > 0);
+            Assert.IsTrue(enrollmentsWithoutGrade > 0);
+        }
+    }
+}
