+using System;
+using System.IO;
+using System.Linq;
+using ContosoUniversity.Controllers;
+using ContosoUniversity.Data;
+using ContosoUniversity.Models;
+using Microsoft.AspNetCore.Hosting;
+using Microsoft.AspNetCore.Http;
+using Microsoft.AspNetCore.Mvc;
+using Microsoft.Extensions.Logging;
+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using Moq;
+
+namespace ContosoUniversity.Tests.Controllers
+{
+    [TestClass]
+    public sealed class CoursesControllerTests
+    {
+        private SchoolContext _context;
+        private CoursesController _controller;
+        private Mock<IWebHostEnvironment> _envMock;
+        private Mock<ILogger<CoursesController>> _loggerMock;
+
+        [TestInitialize]
+        public void Setup()
+        {
+            TestHelpers.DrainNotificationQueue();
+            _context = TestHelpers.CreateContext();
+            SeedData(_context);
+            _envMock = new Mock<IWebHostEnvironment>();
+            _envMock.Setup(e => e.WebRootPath).Returns((string)null);
+            _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
+            _loggerMock = new Mock<ILogger<CoursesController>>();
+            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
+        }
+
+        [TestCleanup]
+        public void Cleanup()
+        {
+            TestHelpers.DrainNotificationQueue();
+            _controller?.Dispose();
+            _context?.Dispose();
+        }
+
+        private static void SeedData(SchoolContext context)
+        {
+            var dept = new Department
+            {
+                Name = "Engineering",
+                Budget = 100000,
+                StartDate = DateTime.Parse("2007-09-01")
+            };
+            context.Departments.Add(dept);
+            context.SaveChanges();
+
+            context.Courses.AddRange(
+                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
+                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID }
+            );
+            context.SaveChanges();
+        }
+
+        // --- Index ---
+
+        [TestMethod]
+        public void Index_ReturnsCoursesList()
+        {
+            var result = _controller.Index() as ViewResult;
+
+            Assert.IsNotNull(result);
+            var model = result.Model as System.Collections.Generic.List<Course>;
+            Assert.IsNotNull(model);
+            Assert.AreEqual(2, model.Count);
+        }
+
+        // --- Details ---
+
+        [TestMethod]
+        public void Details_NullId_ReturnsBadRequest()
+        {
+            var result = _controller.Details(null);
+            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
+            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
+        }
+
+        [TestMethod]
+        public void Details_ValidId_ReturnsViewWithCourse()
+        {
+            var result = _controller.Details(1050) as ViewResult;
+
+            Assert.IsNotNull(result);
+            var model = result.Model as Course;
+            Assert.AreEqual("Chemistry", model.Title);
+        }
+
+        // --- Create GET ---
+
+        [TestMethod]
+        public void Create_Get_ReturnsViewWithNewCourse()
+        {
+            var result = _controller.Create() as ViewResult;
+
+            Assert.IsNotNull(result);
+            Assert.IsNotNull(result.Model);
+            Assert.IsInstanceOfType(result.Model, typeof(Course));
+        }
+
+        // --- Create POST ---
+
+        [TestMethod]
+        public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
+        {
+            var course = new Course
+            {
+                CourseID = 9999,
+                Title = "NewCourse",
+                Credits = 4,
+                DepartmentID = _context.Departments.First().DepartmentID
+            };
+
+            var result = _controller.Create(course, null) as RedirectToActionResult;
+
+            Assert.IsNotNull(result);
+            Assert.AreEqual("Index", result.ActionName);
+            Assert.IsTrue(_context.Courses.Any(c => c.CourseID == 9999));
+        }
+
+        [TestMethod]
+        public void Create_Post_InvalidModelState_ReturnsView()
+        {
+            _controller.ModelState.AddModelError("Title", "Required");
+            var course = new Course { CourseID = 8888, Credits = 3 };
+
+            var result = _controller.Create(course, null) as ViewResult;
+
+            Assert.IsNotNull(result);
+        }
+
+        [TestMethod]
+        public void Create_Post_InvalidImageExtension_ReturnsViewWithError()
+        {
+            var course = new Course
+            {
+                CourseID = 7777,
+                Title = "Test",
+                Credits = 3,
+                DepartmentID = _context.Departments.First().DepartmentID
+            };
+
+            var fileMock = new Mock<IFormFile>();
+            fileMock.Setup(f => f.FileName).Returns("test.exe");
+            fileMock.Setup(f => f.Length).Returns(1024);
+
+            var result = _controller.Create(course, fileMock.Object) as ViewResult;
+
+            Assert.IsNotNull(result);
+            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+        }
+
+        [TestMethod]
+        public void Create_Post_FileTooLarge_ReturnsViewWithError()
+        {
+            var course = new Course
+            {
+                CourseID = 6666,
+                Title = "Test",
+                Credits = 3,
+                DepartmentID = _context.Departments.First().DepartmentID
+            };
+
+            var fileMock = new Mock<IFormFile>();
+            fileMock.Setup(f => f.FileName).Returns("test.jpg");
+            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB > 5MB
+
+            var result = _controller.Create(course, fileMock.Object) as ViewResult;
+
+            Assert.IsNotNull(result);
+            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+        }
+
+        // --- Edit GET ---
+
+        [TestMethod]
+        public void Edit_Get_NullId_ReturnsBadRequest()
+        {
+            var result = _controller.Edit((int?)null);
+            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
+            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
+        }
+
+        [TestMethod]
+        public void Edit_Get_InvalidId_ReturnsNotFound()
+        {
+            var result = _controller.Edit(9999);
+            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
+        }
+
+        [TestMethod]
+        public void Edit_Get_ValidId_ReturnsViewWithCourse()
+        {
+            var result = _controller.Edit(1050) as ViewResult;
+
+            Assert.IsNotNull(result);
+            var model = result.Model as Course;
+            Assert.AreEqual("Chemistry", model.Title);
+        }
+
+        // --- Edit POST ---
+
+        [TestMethod]
+        public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
+        {
+            // Detach existing tracked entity
+            var existing = _context.Courses.Find(1050);
+            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
+
+            var course = new Course
+            {
+                CourseID = 1050,
+                Title = "Updated Chemistry",
+                Credits = 4,
+                DepartmentID = _context.Departments.First().DepartmentID
+            };
+
+            var result = _controller.Edit(course, null) as RedirectToActionResult;
+
+            Assert.IsNotNull(result);
+            Assert.AreEqual("Index", result.ActionName);
+        }
+
+        [TestMethod]
+        public void Edit_Post_InvalidImageExtension_ReturnsViewWithError()
+        {
+            var existing = _context.Courses.Find(1050);
+            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
+
+            var course = new Course
+            {
+                CourseID = 1050,
+                Title = "Chemistry",
+                Credits = 3,
+                DepartmentID = _context.Departments.First().DepartmentID
+            };
+
+            var fileMock = new Mock<IFormFile>();
+            fileMock.Setup(f => f.FileName).Returns("file.pdf");
+            fileMock.Setup(f => f.Length).Returns(1024);
+
+            var result = _controller.Edit(course, fileMock.Object) as ViewResult;
+
+            Assert.IsNotNull(result);
+            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+        }
+
+        [TestMethod]
+        public void Edit_Post_FileTooLarge_ReturnsViewWithError()
+        {
+            var existing = _context.Courses.Find(1050);
+            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
+
+            var course = new Course
+            {
+                CourseID = 1050,
+                Title = "Chemistry",
+                Credits = 3,
+                DepartmentID = _context.Departments.First().DepartmentID
+            };
+
+            var fileMock = new Mock<IFormFile>();
+            fileMock.Setup(f => f.FileName).Returns("file.png");
+            fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB
+
+            var result = _controller.Edit(course, fileMock.Object) as ViewResult;
+
+            Assert.IsNotNull(result);
+            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+        }
+
+        // --- Delete GET ---
+
+        [TestMethod]
+        public void Delete_Get_NullId_ReturnsBadRequest()
+        {
+            var result = _controller.Delete(null);
+            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
+            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
+        }
+
+        [TestMethod]
+        public void Delete_Get_ValidId_ReturnsViewWithCourse()
+        {
+            var result = _controller.Delete(1050) as ViewResult;
+
+            Assert.IsNotNull(result);
+            var model = result.Model as Course;
+            Assert.AreEqual("Chemistry", model.Title);
+        }
+
+        // --- DeleteConfirmed ---
+
+        [TestMethod]
+        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
+        {
+            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;
+
+            Assert.IsNotNull(result);
+            Assert.AreEqual("Index", result.ActionName);
+            Assert.IsFalse(_context.Courses.Any(c => c.CourseID == 1050));
+        }
+
+        [TestMethod]
+        public void DeleteConfirmed_SendsDeleteNotification()
+        {
+            _controller.DeleteConfirmed(4022);
+
+            var svc = new ContosoUniversity.Services.NotificationService();
+            var notification = svc.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("DELETE", notification.Operation);
+            Assert.IsTrue(notification.Message.Contains("Course"));
+        }
+
+        // --- Image Extension Validation ---
+
+        [TestMethod]
+        [DataRow(".jpg", true, DisplayName = "JPG allowed")]
+        [DataRow(".jpeg", true, DisplayName = "JPEG allowed")]
+        [DataRow(".png", true, DisplayName = "PNG allowed")]
+        [DataRow(".gif", true, DisplayName = "GIF allowed")]
+        [DataRow(".bmp", true, DisplayName = "BMP allowed")]
+        [DataRow(".exe", false, DisplayName = "EXE rejected")]
+        [DataRow(".pdf", false, DisplayName = "PDF rejected")]
+        [DataRow(".svg", false, DisplayName = "SVG rejected")]
+        public void Create_Post_ImageExtensionValidation(string extension, bool shouldAccept)
+        {
+            var course = new Course
+            {
+                CourseID = 5555,
+                Title = "ExtTest",
+                Credits = 3,
+                DepartmentID = _context.Departments.First().DepartmentID
+            };
+
+            var fileMock = new Mock<IFormFile>();
+            fileMock.Setup(f => f.FileName).Returns($"test{extension}");
+            fileMock.Setup(f => f.Length).Returns(1024);
+
+            if (shouldAccept)
+            {
+                // For valid extensions, set up the file copy
+                fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
+            }
+
+            var result = _controller.Create(course, fileMock.Object);
+
+            if (shouldAccept)
+            {
+                // Valid extensions should redirect (or at least not have extension error)
+                // Depending on file system access, may succeed or fail; check no extension error
+                var hasExtensionError = _controller.ModelState.ContainsKey("teachingMaterialImage") &&
+                    _controller.ModelState["teachingMaterialImage"].Errors.Any(e => e.ErrorMessage.Contains("valid image file"));
+                Assert.IsFalse(hasExtensionError, $"Extension {extension} should be accepted");
+            }
+            else
+            {
+                Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
+            }
+        }
+    }
+}
